import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface MacrosBreakdown {
  carbohydrates: number;
  proteins: number;
  fats: number;
}

interface Meal {
  meal: string;
  calories: number;
}

interface NutritionData {
  caloriesConsumed: number;
  macrosBreakdown: MacrosBreakdown;
  mealCount: number;
  dailyIntake: Meal[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const nutritionData = response.data as NutritionData;
  const metaData = response.meta as MetaData;
  const { caloriesConsumed, macrosBreakdown, dailyIntake } = nutritionData;

  const pieData = [
    { value: macrosBreakdown.carbohydrates, label: 'Carbs', color: metaData.primaryColor },
    { value: macrosBreakdown.proteins, label: 'Proteins', color: metaData.accentColor },
    { value: macrosBreakdown.fats, label: 'Fats', color: '#FF9800' },
  ];

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ mb: 1, color: metaData.primaryColor }}>
              Nutrition Summary
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Calories Consumed
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#4CAF50' }}>
              {caloriesConsumed} kcal
            </Typography>
          </Box>

          <PieChart
            height={140}
            series={[
              {
                data: pieData.map((item) => item.value),
                color: pieData.map((item) => item.color),
                innerRadius: 0.5,
              },
            ]}
            labels={pieData.map((item) => item.label)}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
          />

          <Stack spacing={1.5}>
            {dailyIntake.map((meal) => (
              <Box key={meal.meal}>
                <Typography variant="body2" fontWeight={500}>
                  {meal.meal}: {meal.calories} kcal
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
